using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Seeds;
using MVZ2.GameContent.Stages;
using MVZ2Logic;
using MVZ2Logic.IZombie;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Level;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.IZombie
{
    [IZombieLayoutDefinition(VanillaIZombieLayoutNames.Chimera)]
    public class Chimera : IZombieLayoutDefinition
    {
        public Chimera(string nsp, string name) : base(nsp, name, 5)
        {
            Blueprints = new NamespaceID[]
            {
                VanillaEnemyID.imp,
                VanillaEnemyID.leatherCappedZombie,
                VanillaEnemyID.skeletonHorse,
                VanillaEnemyID.ironHelmettedZombie,
                VanillaBlueprintID.ufoGreen,
                VanillaEnemyID.spider,
                VanillaEnemyID.skeletonWarrior,
            };
        }
        public override void Fill(IIZombieMap map, RandomGenerator rng)
        {
            var level = map.Level;

            SpawnAt(level, 0, 0, VanillaContraptionID.spikeBlock);
            SpawnAt(level, 0, 1, VanillaContraptionID.triplenser);
            SpawnAt(level, 0, 2, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 0, 3, VanillaContraptionID.lightningOrb);
            SpawnAt(level, 0, 4, VanillaContraptionID.stoneDropper);

            SpawnAt(level, 1, 0, VanillaContraptionID.furnace);
            SpawnAt(level, 1, 1, VanillaContraptionID.hellfire);
            SpawnAt(level, 1, 2, VanillaContraptionID.beacon);
            SpawnAt(level, 1, 3, VanillaContraptionID.soulFurnace);
            SpawnAt(level, 1, 4, VanillaContraptionID.furnace);

            SpawnAt(level, 2, 0, VanillaContraptionID.splitenser);
            SpawnAt(level, 2, 1, VanillaContraptionID.furnace);
            SpawnAt(level, 2, 2, VanillaContraptionID.fireworkDispenser);
            SpawnAt(level, 2, 3, VanillaContraptionID.stoneDropper);
            SpawnAt(level, 2, 4, VanillaContraptionID.splitenser);

            SpawnAt(level, 3, 0, VanillaContraptionID.splitenser);
            SpawnAt(level, 3, 1, VanillaContraptionID.furnace);
            SpawnAt(level, 3, 2, VanillaContraptionID.splitenser);
            SpawnAt(level, 3, 3, VanillaContraptionID.beacon);
            SpawnAt(level, 3, 4, VanillaContraptionID.lightningOrb);

            SpawnAt(level, 4, 0, VanillaContraptionID.furnace);
            SpawnAt(level, 4, 1, VanillaContraptionID.punchton);
            SpawnAt(level, 4, 2, VanillaContraptionID.mineTNT);
            SpawnAt(level, 4, 3, VanillaContraptionID.spikeBlock);
            SpawnAt(level, 4, 4, VanillaContraptionID.triplenser);

            

            //SpawnAt(level, 3, 2, VanillaContraptionID.redline);

            //var rlX = level.GetColumnX(3);       // ÁĐ×ó±ßÔµŁ¬Óë±ę×ĽşěĎßŇ»ÖÂ  
            //var rlZ = level.GetLaneCenterZ(2);   // lane 3 µÄÖĐĐÄ  
            //var rlY = level.GetGroundY(rlX, rlZ);

            //level.Spawn(VanillaContraptionID.redline, new Vector3(rlX, rlY, rlZ), null);

            var buffDef = level.Content.GetBuffDefinition<DebugNoRechargeBuff>();
            if (!level.HasBuff(buffDef))
            {
                level.AddBuff(buffDef);
            }

        }
        private void SpawnAt(LevelEngine level, int column, int lane, NamespaceID entityID)
        {
            var x = level.GetEntityColumnX(column);
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            level.Spawn(entityID, new Vector3(x, y, z), null);
        }
    }
}
